#include <iostream>
using namespace std;

int main() {
    int x;
    cout << "Enter number: ";
    cin >> x;
    if (x > 0) {
        cout << "Positive" << endl;
    } else if (x == 0) {
        cout << "Zero" << endl;
    } else {
        cout << "Negative" << endl;
    }
    return 0;
}

